import{_ as a,a as d,b as t,c as i,d as o,e as n,f as l,g as r}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as s,o as p,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"الفهرس الاتحادي الموزع","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Other/federated-distributed-index.md","filePath":"ar-SA/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),u={name:"ar-SA/Other/federated-distributed-index.md"};function b(m,e,f,x,g,q){return p(),c("div",null,[...e[0]||(e[0]=[h('<h1 id="الفهرس-الاتحادي-الموزع" tabindex="-1">الفهرس الاتحادي الموزع <a class="header-anchor" href="#الفهرس-الاتحادي-الموزع" aria-label="Permalink to &quot;الفهرس الاتحادي الموزع&quot;">​</a></h1><p>يسمح federated distributed index لعدة مواقع ImgBed بمشاركة قوائم الملفات فيما بينها.</p><p>ببساطة:</p><ul><li>يمكنك مشاركة مجلدات محددة من موقعك مع الآخرين.</li><li>يمكنك الانضمام إلى node آخر ومزامنة قائمة ملفاته المشتركة إلى لوحة إدارتك.</li><li>ملفات federated مخصصة أساسًا للتصفح والبحث وفتح الروابط. لا يُعاد رفعها إلى تخزينك الخاص.</li></ul><h2 id="أين-تضبطه؟" tabindex="-1">أين تضبطه؟ <a class="header-anchor" href="#أين-تضبطه؟" aria-label="Permalink to &quot;أين تضبطه؟&quot;">​</a></h2><p>افتح:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="العقدة المحلية" loading="lazy"></p><p>تحتوي الصفحة على ثلاثة تبويبات:</p><table tabindex="0"><thead><tr><th>التبويب</th><th>الغرض</th></tr></thead><tbody><tr><td>Local Node</td><td>تفعيل عقدتك، تأكيد النطاق العام، اختيار المجلدات المشتركة، وتحديث outbound index</td></tr><tr><td>Nodes I Joined</td><td>إدارة عقد ImgBed الأخرى التي انضممت إليها</td></tr><tr><td>Nodes Joining Me</td><td>إدارة طلبات الآخرين للانضمام إلى عقدتك</td></tr></tbody></table><h2 id="الإعداد-لأول-مرة" tabindex="-1">الإعداد لأول مرة <a class="header-anchor" href="#الإعداد-لأول-مرة" aria-label="Permalink to &quot;الإعداد لأول مرة&quot;">​</a></h2><ol><li>افتح <code>Local Node</code>.</li><li>فعّل <code>Enable</code>.</li><li>اختر المجلدات التي تريد مشاركتها ضمن <code>Sync folders</code>.</li><li>اضغط <code>Update Outbound Index</code>.</li><li>إذا اكتشف ImgBed تغيّر النطاق، أكد أن النطاق الحالي صحيح قبل المتابعة.</li></ol><p>يمكن اختيار عدة sync folders. إذا كانت القائمة فارغة، فستُشارك كل المجلدات.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>Public domain هو رابط الموقع الذي تستخدمه العقد الأخرى للوصول إلى عقدتك.</p><p>يكتشفه ImgBed تلقائيًا ولا تحتاج إلى إدخاله يدويًا. عند أول تحديث للفهرس، يطلب منك تأكيد ما إذا كان رابط الوصول الحالي هو نطاق الإنتاج.</p><p>إذا غيرت النطاق لاحقًا، سيطلب تحديث الفهرس التأكيد مرة أخرى.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>تحدد Sync folders الملفات التي تُشارك مع federation nodes.</p><p>مثلًا، إذا اخترت فقط:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>فلن ترى العقد الأخرى إلا الملفات داخل هذين المجلدين.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>يحدث قائمة الملفات التي تستطيع العقد الأخرى مزامنتها منك.</p><p>استخدمه عندما:</p><ul><li>تفعّل federation لأول مرة.</li><li>ترفع ملفات تريد مشاركتها.</li><li>تغيّر sync folders.</li><li>تغيّر public domain وتحتاج إلى تأكيده.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> هو مكان الاشتراك في عقد أخرى.</p><p><img src="`+d+'" alt="العقد التي انضممت إليها" loading="lazy"></p><h3 id="طلب-الانضمام-إلى-عقدة-أخرى" tabindex="-1">طلب الانضمام إلى عقدة أخرى <a class="header-anchor" href="#طلب-الانضمام-إلى-عقدة-أخرى" aria-label="Permalink to &quot;طلب الانضمام إلى عقدة أخرى&quot;">​</a></h3><ol><li>اطلب invitation link من مالك العقدة الأخرى.</li><li>الصقه في مربع الإدخال.</li><li>اضغط <code>Request to Join</code>.</li><li>انتظر موافقة المالك الآخر من لوحة إدارته.</li></ol><p>بعد الموافقة تصبح حالة العقدة approved.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p>يقوم <code>Update Inbound Index</code> بمزامنة قوائم الملفات من العقد التي انضممت إليها.</p><p>استخدمه عندما:</p><ul><li>يوافق المالك الآخر للتو على طلبك.</li><li>يخبرك المالك الآخر أن المحتوى المشترك تحدّث.</li><li>تريد تحديث كل قوائم federation التي اشتركت بها.</li></ul><p>لتحديث عقدة واحدة فقط، اضغط <code>Update Index</code> في بطاقة تلك العقدة.</p><p><img src="'+t+'" alt="تحديث الفهرس" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>إذا لم تعد تريد مزامنة عقدة، اضغط <code>Unsubscribe</code>.</p><p>بعد إلغاء الاشتراك، يُزال federated index الخاص بتلك العقدة من موقعك المحلي.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> هو مكان التعامل مع طلبات الآخرين.</p><p><img src="'+i+'" alt="العقد التي تنضم إلي" loading="lazy"></p><h3 id="إنشاء-invitation-link" tabindex="-1">إنشاء Invitation Link <a class="header-anchor" href="#إنشاء-invitation-link" aria-label="Permalink to &quot;إنشاء Invitation Link&quot;">​</a></h3><ol><li>تأكد أن local node مفعلة.</li><li>اضغط <code>Update Outbound Index</code> مرة واحدة على الأقل حتى يؤكد ImgBed public domain.</li><li>افتح <code>Nodes Joining Me</code>.</li><li>اضغط <code>Reset Invitation Link</code>.</li><li>انسخ invitation link وأرسله إلى المالك الآخر.</li></ol><p>إذا كان invitation link فارغًا، فغالبًا لم يتم تأكيد public domain بعد. ارجع إلى <code>Local Node</code> واضغط <code>Update Outbound Index</code>.</p><h3 id="معالجة-طلبات-الانضمام" tabindex="-1">معالجة طلبات الانضمام <a class="header-anchor" href="#معالجة-طلبات-الانضمام" aria-label="Permalink to &quot;معالجة طلبات الانضمام&quot;">​</a></h3><p>عندما يرسل شخص طلبًا، يظهر في قائمة <code>Nodes Joining Me</code>.</p><table tabindex="0"><thead><tr><th>الإجراء</th><th>المعنى</th></tr></thead><tbody><tr><td>Approve</td><td>يسمح للعقدة الأخرى بمزامنة قائمة ملفاتك المشتركة</td></tr><tr><td>Reject</td><td>يرفض طلب الانضمام</td></tr><tr><td>Delete</td><td>يحذف سجلًا مكتملًا</td></tr><tr><td>Check Status</td><td>يتحقق هل ما زال الطرف الآخر يحتفظ بالعلاقة</td></tr></tbody></table><p>بعد الموافقة، يحتاج الطرف الآخر إلى الضغط على <code>Update Inbound Index</code> قبل أن تظهر ملفاتك المشتركة لديه.</p><p><img src="'+o+'" alt="الموافقة على عقدة مدعوة" loading="lazy"></p><h2 id="الرسائل" tabindex="-1">الرسائل <a class="header-anchor" href="#الرسائل" aria-label="Permalink to &quot;الرسائل&quot;">​</a></h2><p>بعد الموافقة على العلاقة، اضغط <code>Message</code> في بطاقة العقدة.</p><p>الرسائل مخصصة للتواصل حول علاقة federation فقط. لا تغيّر الملفات أو الوسوم أو المجلدات أو الصلاحيات.</p><p><img src="'+n+'" alt="الرسائل" loading="lazy"></p><h2 id="عرض-federated-files" tabindex="-1">عرض Federated Files <a class="header-anchor" href="#عرض-federated-files" aria-label="Permalink to &quot;عرض Federated Files&quot;">​</a></h2><p>بعد اكتمال المزامنة، ارجع إلى قائمة الملفات في لوحة الإدارة.</p><p>في أعلى الصفحة يمكنك التبديل بين الملفات المحلية و federated files. داخل federated files يمكنك تصفح المحتوى المتزامن.</p><p>ملفات federated مخصصة للعرض والبحث والمعاينة ونسخ الروابط. ليست ملفات محلية، لذلك لا يمكنك نقلها أو حذفها أو إعادة وسمها أو نسخها احتياطيًا من موقعك.</p><p><img src="'+l+'" alt="ملفات federated في الإدارة" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="لماذا-يطلب-مني-إعادة-التقديم-بسبب-عدم-وجود-relationship-record؟" tabindex="-1">لماذا يطلب مني إعادة التقديم بسبب عدم وجود relationship record؟ <a class="header-anchor" href="#لماذا-يطلب-مني-إعادة-التقديم-بسبب-عدم-وجود-relationship-record؟" aria-label="Permalink to &quot;لماذا يطلب مني إعادة التقديم بسبب عدم وجود relationship record؟&quot;">​</a></h3><p>يعني ذلك غالبًا أن الطرف الآخر حذفك وأزال السجل، لذلك لم تعد العلاقة موجودة. أرسل طلب انضمام جديدًا.</p><p><img src="'+r+'" alt="إعادة التقديم عند عدم وجود سجل علاقة" loading="lazy"></p><h3 id="لماذا-لا-أرى-الملفات-بعد-الانضمام؟" tabindex="-1">لماذا لا أرى الملفات بعد الانضمام؟ <a class="header-anchor" href="#لماذا-لا-أرى-الملفات-بعد-الانضمام؟" aria-label="Permalink to &quot;لماذا لا أرى الملفات بعد الانضمام؟&quot;">​</a></h3><p>تحقق من:</p><ol><li>المالك الآخر وافق على طلبك.</li><li>المالك الآخر ضغط <code>Update Outbound Index</code>.</li><li>أنت ضغطت <code>Update Inbound Index</code>.</li><li>مجلدات sync folders لدى المالك الآخر تتضمن المجلدات التي يريد مشاركتها.</li></ol><h3 id="ماذا-أفعل-عند-اكتشاف-تغيّر-النطاق؟" tabindex="-1">ماذا أفعل عند اكتشاف تغيّر النطاق؟ <a class="header-anchor" href="#ماذا-أفعل-عند-اكتشاف-تغيّر-النطاق؟" aria-label="Permalink to &quot;ماذا أفعل عند اكتشاف تغيّر النطاق؟&quot;">​</a></h3><p>إذا كنت تفتح لوحة الإدارة عبر نطاق الإنتاج، أكد وتابع.</p><p>إذا كنت تستخدم عنوانًا مؤقتًا، ألغِ العملية، وافتح لوحة الإدارة عبر نطاق الإنتاج ثم جرّب مرة أخرى.</p><h3 id="ماذا-تعني-قائمة-sync-folder-فارغة؟" tabindex="-1">ماذا تعني قائمة Sync Folder فارغة؟ <a class="header-anchor" href="#ماذا-تعني-قائمة-sync-folder-فارغة؟" aria-label="Permalink to &quot;ماذا تعني قائمة Sync Folder فارغة؟&quot;">​</a></h3><p>تعني أن كل المجلدات مشتركة.</p><p>لمشاركة مجلدات محددة فقط، اخترها يدويًا.</p><h3 id="الفرق-بين-تحديث-outbound-و-inbound-index" tabindex="-1">الفرق بين تحديث Outbound و Inbound Index <a class="header-anchor" href="#الفرق-بين-تحديث-outbound-و-inbound-index" aria-label="Permalink to &quot;الفرق بين تحديث Outbound و Inbound Index&quot;">​</a></h3><table tabindex="0"><thead><tr><th>الزر</th><th>المعنى المبسط</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>يحدّث ما يستطيع الآخرون مزامنته مني</td></tr><tr><td>Update Inbound Index</td><td>يحدّث ما زامنته أنا من الآخرين</td></tr></tbody></table>',77)])])}const y=s(u,[["render",b]]);export{_ as __pageData,y as default};
